    private List<List<Integer>> merge(List<List<Integer>> input1, List<List<Integer>> input2) {
        List<List<Integer>> res = new ArrayList<>();
        int i=0, j=0;
        while(i < input1.size() || j < input2.size()) {
            List<Integer> a = i < input1.size() ? input1.get(i) : null;
            List<Integer> b = j < input2.size() ? input2.get(j) : null;
            if (a != null && b != null) {
                if (a.get(0) == b.get(0)) {
                    res.add(Arrays.asList(a.get(0), a.get(1) + b.get(1)));
                    i++;
                    j++;
                } else if (a.get(0) < b.get(0)) {
                    res.add(Arrays.asList(a.get(0), a.get(1) + b.get(1)));
                    i++;
                } else if (a.get(0) > b.get(0)) {
                    res.add(Arrays.asList(b.get(0), a.get(1) + b.get(1)));
                    j++;
                }
            } else if (a!=null) {
                res.add(a);
                i++;
            } else if (b != null) {
                res.add(b);
                j++;
            }
        }
        return res;
    }

